            box-shadow: inset 0 2px 5px #0a1c24;
            letter-spacing: 0.5px;
        }
        .food-stats span {
            color: #fcd787;
            font-weight: 700;
        }
        .hint {
            background: #173e4b;
            padding: 6px 18px;
            border-radius: 30px;
